import { Context, Effect, Layer } from "effect";

export type BackendClockService = {
  readonly nowIso: () => string;
  readonly nowMs: () => number;
};

export const BackendClock = Context.Service<BackendClockService>("relay/BackendClock");

export const BackendClockLive = Layer.succeed(BackendClock)({
  nowIso: () => new Date().toISOString(),
  nowMs: () => Date.now()
});

export const BackendRuntimeLive = BackendClockLive;

export type BackendServices = Context.Service.Identifier<typeof BackendClock>;
export type BackendEffect<A, E = unknown, R = BackendServices> = Effect.Effect<A, E, R>;

export const runBackendEffect = <A, E>(effect: Effect.Effect<A, E, BackendServices>): Promise<A> =>
  Effect.runPromise(Effect.provide(effect, BackendRuntimeLive));

export const fromPromise = <A>(evaluate: (signal: AbortSignal) => PromiseLike<A>): Effect.Effect<A, unknown> =>
  Effect.tryPromise({
    try: evaluate,
    catch: (cause) => cause
  });

export const fromSync = <A>(evaluate: () => A): Effect.Effect<A, unknown> =>
  Effect.suspend(() => {
    try {
      return Effect.succeed(evaluate());
    } catch (cause) {
      return Effect.fail(cause);
    }
  });

import test from "node:test";
import assert from "node:assert/strict";
import { Effect } from "effect";
import { access, mkdtemp, readFile, writeFile } from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import type { BrowserWindow } from "electron";
import { cancelCodexRun, readCodexRunEvents, startCodexRun, type CodexRunDependencies } from "../src/main/services/codex";
import { BackendClock, runBackendEffect } from "../src/main/services/effectRuntime";
