n  switch (status) {\n    case \"idle\":\n      return \"Idle\";\n    case \"running\":\n      return \"Running\";\n    case \"blocked\":\n      return \"Blocked\";\n    case \"failed\":\n      return \"Failed\";\n    case \"completed\":\n      return \"Codex Done\";\n    case \"cancelled\":\n      return \"Cancelled\";\n    case \"drafting\":\n      return \"Drafting\";\n    default:\n      return \"Idle\";\n  }\n};\n\nconst eventText = (event: RendererRunEvent): string => {\n  switch (event.type) {\n    case \"run.started\":\n      return `Run started (${event.threadId})`;\n    case \"agent.message.delta\":\n    case \"agent.message.completed\":\n      return event.text;\n    case \"command.started\":\n      return `$ ${event.command}`;\n    case \"command.output\":\n      return event.text;\n    case \"command.completed\":\n      return `Command ${event.status}`;\n    case \"file.change\":\n      return event.summary ?? event.path;\n    case \"approval.requested\":\n      return `Approval requested: ${event.kind}`;\n    case \"approval.resolved\":\n      return `Approval ${event.decision}`;\n    case \"ticket.status_changed\":\n      return `Status moved from ${event.fromStatus} to ${event.toStatus}`;\n    case \"clarification.requested\":\n      return `${event.questions.length} clarification question${event.questions.length === 1 ? \"\" : \"s\"} requested`;\n    case \"run.completed\":\n      return event.finalResponse;\n    case \"run.failed\":\n      return event.message;\n    default:\n      return \"\";\n  }\n};\n\nconst isMarkdownConsoleEvent = (event: RendererRunEvent): boolean =>\n  event.type === \"agent.message.completed\" || event.type === \"run.completed\";\n\n// Markdown audit: create-ticket drafts, ticket detail bodies, clarification text,\n// and generated Codex completion/final-response console events use MarkdownBlock.\n// Board excerpts and command output stay plain text because they are summaries/logs.\nconst copyToast = (kind: \"markdown\" | 