ning risks or follow-up work\n   611\t\n   612\tTicket:\n   613\t${ticketMarkdown}`;\n   614\t\n   615\tconst updateTicketRunState = async (\n   616\t  projectPath: string,\n   617\t  ticketId: string,\n   618\t  patch: Partial<{\n   619\t    codexThreadId: string | null;\n   620\t    runStatus: \"idle\" | \"drafting\" | \"running\" | \"blocked\" | \"failed\" | \"completed\" | \"cancelled\";\n   621\t    lastRunId: string | null;\n   622\t    status: string;\n   623\t    markdown: string;\n   624\t  }>\n   625\t): Promise<void> => {\n   626\t  const ticket = await readTicket(projectPath, ticketId);\n   627\t  await writeTicket(projectPath, {\n   628\t    ...ticket,\n   629\t    markdown: patch.markdown ?? ticket.markdown,\n   630\t    frontMatter: {\n   631\t      ...ticket.frontMatter,\n   632\t      codexThreadId: patch.codexThreadId !== undefined ? patch.codexThreadId : ticket.frontMatter.codexThreadId,\n   633\t      runStatus: patch.runStatus ?? ticket.frontMatter.runStatus,\n   634\t      lastRunId: patch.lastRunId !== undefined ? patch.lastRunId : ticket.frontMatter.lastRunId,\n   635\t      status: patch.status ?? ticket.frontMatter.status\n   636\t    }\n   637\t  });\n   638\t};\n   639\t\n   640\tconst beginRun = async (\n   641\t  browserWindow: BrowserWindow,\n   642\t  input: StartRunInput,\n   643\t  resume: boolean\n   644\t): Promise<{ runId: string; threadId: string }> => {\n   645\t  await logInfo(\"codex:run\", \"starting run\", { projectPath: input.projectPath, ticketId: input.ticketId, resume, freshThread: input.freshThread });\n   646\t  const config = await readProjectConfig(input.projectPath);\n   647\t  if (!config.settings.codexExecutionEnabled) {\n   648\t    throw new Error(\"Codex execution is disabled for this project.\");\n   649\t  }\n   650\t\n   651\t  const git = await isGitRepository(input.projectPath);\n   652\t  if (!git && !config.settings.allowNonGitCodexRuns) {\n   653\t    throw new Error(\"This project is not a Git repository. Enable non-Git Codex runs in project settings first.\");\n   654\t  }\n   655\t\n   656\t  const ticket = await readTicket(input.projectPath, input.ticketId);\n   657\t  if (ticket.frontMatter.status === \"not_doing\") {\n   658\t    throw new Error(\"Move this ticket out of Not Doing before starting Codex.\");\n   659\t  }\n   660\t\n   661\t  const clarifications = await readClarificationQuestions(input.projectPath, input.ticketId);\n   662\t  const codex = createCodex();\n   663\t  const options = await threadOptionsForProject(input.projectPath);\n   664\t  const runId = newId(\"run\");\n   665\t  const existingThreadId = resume && !input.freshThread ? ticket.frontMatter.codexThreadId : null;\n   666\t  const thread: Thread = existingThreadId ? codex.resumeThread(existingThreadId, options) : codex.startThread(options);\n   667\t  const abortController = new AbortController();\n   668\t  const prompt = buildExecutionPrompt(ticket.markdown, clarifications);\n   669\t  const outputOffsets = new Map<string, number>();\n   670\t  activeRuns.set(runId, {\n   671\t    abortController,\n   672\t    ticketId: input.ticketId,\n   673\t    projectPath: input.projectPath\n   674\t  });\n   675\t\n   676\t  const status = config.columns.some((column) => column.id === \"in_progress\") ? \"in_progress\" : ticket.frontMatter.status;\n   677\t  await updateTicketRunState(input.projectPath, input.ticketId, {\n   678\t    runStatus: \"running\",\n   679\t    lastRunId: runId\n   680\t  });\n   681\t  const transitioned = await transitionTicketStatus(input.projectPath, input.ticketId, status, {\n   682\t    actor: \"codex\",\n   683\t    source: \"agent_execution\",\n   684\t    runId\n   685\t  });\n   686\t\n   687\t  let currentThreadId = existingThreadId ?? thread.id ?? `pending_${runId}`;\n   688\t  if (ticket.frontMatter.status !== transitioned.frontMatter.status) {\n   689\t    await emitRunEvent(browserWindow, input.projectPath, input.ticketId, runId, currentThreadId, {