  735\t            resolveOnce(currentThreadId);\n   736\t            continue;\n   737\t          }\n   738\t\n   739\t          if (event.type === \"item.started\" || event.type === \"item.updated\" || event.type === \"item.completed\") {\n   740\t            const text = finalTextFromItem(event.item);\n   741\t            if (event.item.type === \"agent_message\" && text) finalResponse = text;\n   742\t            const normalized = normalizeItemEvent(event, outputOffsets);\n   743\t            for (const relayEvent of normalized) {\n   744\t              await emitRunEvent(browserWindow, input.projectPath, input.ticketId, runId, currentThreadId, relayEvent);\n   745\t            }\n   746\t            continue;\n   747\t          }\n   748\t\n   749\t          if (event.type === \"turn.failed\" || event.type === \"error\") {\n   750\t            const message = event.type === \"turn.failed\" ? event.error.message : event.message;\n   751\t            await updateTicketRunState(input.projectPath, input.ticketId, { runStatus: \"failed\" });\n   752\t            await emitRunEvent(browserWindow, input.projectPath, input.ticketId, runId, currentThreadId, {\n   753\t              type: \"run.failed\",\n   754\t              message,\n   755\t              timestamp: nowIso()\n   756\t            });\n   757\t            resolveOnce(currentThreadId);\n   758\t            return;\n   759\t          }\n   760\t\n   761\t          if (event.type === \"turn.completed\") {\n   762\t            const updated = await readTicket(input.projectPath, input.ticketId);\n   763\t            const handoff = finalResponse || \"Codex completed the run without a final text response.\";\n   764\t            const clarificationRequest = extractClarificationRequest(handoff);\n   765\t            if (clarificationRequest.length > 0) {\n   766\t              const questions = await createClarificationQuestions(input.projectPath, input.ticketId, clarificationRequest, {\n   767\t                actor: \"codex\",\n   768\t                source: \"agent_execution\",\n   769\t                runId,\n   770\t                codexThreadId: currentThreadId\n   771\t              });\n   772\t              const targetStatus = config.columns.some((column) => column.id === \"needs_clarification\")\n   773\t                ? \"needs_clarification\"\n   774\t                : updated.frontMatter.status;\n   775\t              await updateTicketRunState(input.projectPath, input.ticketId, {\n   776\t                runStatus: \"blocked\",\n   777\t                lastRunId: runId,\n   778\t                markdown: appendCodexHandoff(updated.markdown, handoff)\n   779\t              });\n   780\t              const blockedTransition = await transitionTicketStatus(input.projectPath, input.ticketId, targetStatus, {\n   781\t                actor: \"codex\",\n   782\t                source: \"agent_execution\",\n   783\t                runId\n   784\t              });\n   785\t              if (updated.frontMatter.status !== blockedTransition.frontMatter.status) {\n   786\t                await emitRunEvent(browserWindow, input.projectPath, input.ticketId, runId, currentThreadId, {\n   787\t                  type: \"ticket.status_changed\",\n   788\t                  fromStatus: updated.frontMatter.status,\n   789\t                  toStatus: blockedTransition.frontMatter.status,\n   790\t                  actor: \"codex\",\n"}}
