565	test("codex run cancellation aborts the stream and cleans up the active run", async () => {
566	  const projectPath = await createProject();
567	  await allowNonGitRuns(projectPath);
568	  const ticket = await createTicket(projectPath, {
569	    title: "Cancellation cleanup",
570	    priority: "medium",
571	    labels: ["codex"],
572	    markdown: "# Cancellation cleanup\n"
573	  });
574	  const { window, events } = createFakeWindow();
575	  let capturedSignal: AbortSignal | undefined;
576	  const dependencies: CodexRunDependencies = {
577	    createRunId: () => "run_cancel_cleanup",
578	    createCodexClient: () =>
579	      ({
580	        startThread: () => ({
581	          id: "thread_cancel_cleanup",
582	          runStreamed: async (_prompt: string, options?: { signal?: AbortSignal }) => {
583	            capturedSignal = options?.signal;
584	            return {
585	              events: (async function*() {
586	                yield { type: "thread.started", thread_id: "thread_cancel_cleanup" };
587	                await new Promise<void>((_resolve, reject) => {
588	                  if (capturedSignal?.aborted) {
589	                    const error = new Error("The operation was aborted.");
590	                    error.name = "AbortError";
591	                    reject(error);
592	                    return;
593	                  }
594	                  capturedSignal?.addEventListener(
595	                    "abort",
596	                    () => {
597	                      const error = new Error("The operation was aborted.");
598	                      error.name = "AbortError";
599	                      reject(error);
600	                    },
601	                    { once: true }
602	                  );
603	                });
604	              })()
605	            };
606	          }
607	        }),
608	        resumeThread: () => {
609	          throw new Error("resumeThread should not be used for a fresh run.");
610	        }
611	      }) as CodexRunDependencies["createCodexClient"] extends () => infer Client ? Client : never
612	  };
613	
614	  await startCodexRun(window, { projectPath, ticketId: ticket.frontMatter.id }, dependencies);
615	  await waitFor(() => events.some((event) => event.type === "run.started"), "run start before cancellation");
616	  await cancelCodexRun("run_cancel_cleanup");
617	
618	  assert.equal(capturedSignal?.aborted, true);
619	  await waitFor(() => events.some((event) => event.type === "run.failed"), "run cancellation finalizer");
620	  assert.equal((await readTicket(projectPath, ticket.frontMatter.id)).frontMatter.runStatus, "cancelled");
621	
622	  const cancelled = await readTicket(projectPath, ticket.frontMatter.id);
623	  await writeTicket(projectPath, {
624	    ...cancelled,
625	    frontMatter: {
626	      ...cancelled.frontMatter,
627	      runStatus: "failed"
628	    }
629	  });
630	  await cancelCodexRun("run_cancel_cleanup");
631	  assert.equal((await readTicket(projectPath, ticket.frontMatter.id)).frontMatter.runStatus, "failed");
632	
633	  const persistedEvents = await readCodexRunEvents(projectPath, ticket.frontMatter.id, "run_cancel_cleanup");
634	  assert.equal(persistedEvents.some((event) => event.type === "run.failed" && /aborted/i.test(event.message)), true);
635	});
